<form id="form_nrp" class="form-horizontal nrp-toolbar"><div class="form-group"><label class="control-label col-md-2">As Of</label><div class="col-md-2"><input type="date" id="current_as_of_date" name="current_as_of_date" class="form-control" value="<?=date('Y-m-d');?>"></div><label class="control-label col-md-2">Compare As Of</label><div class="col-md-2"><input type="date" id="compare_as_of_date" name="compare_as_of_date" class="form-control"></div><div class="col-md-4"><button type="submit" id="btn_filter" class="btn btn-primary"><i class="fa fa-search"></i> Tampilkan</button> <button type="button" id="btn_default_compare" class="btn btn-default"><i class="fa fa-refresh"></i> Akhir Bulan Sebelumnya</button></div></div></form>
