<script>
$(function(){function fmt(d){var m=('0'+(d.getMonth()+1)).slice(-2),day=('0'+d.getDate()).slice(-2);return d.getFullYear()+'-'+m+'-'+day;}function defaultCompare(){var d=new Date($('#current_as_of_date').val());if(isNaN(d))return;d.setDate(1);d.setDate(0);$('#compare_as_of_date').val(fmt(d));}
function qs(){return $('#form_nrp').serialize();}function loadReport(){$('#nrp_alert').hide().text('');$('#nrp_result').html('<div class="text-center" style="padding:30px"><i class="fa fa-spinner fa-spin fa-2x"></i><br>Loading...</div>');$('#btn_filter').prop('disabled',true);$.ajax({url:'<?=base_admin();?>modul/finance_report/finance_report_neraca_perbandingan_periode_action.php?act=filter',type:'POST',dataType:'json',data:qs()}).done(function(res){if(res.status==='success')$('#nrp_result').html(res.html);else{$('#nrp_result').html('<div class="alert alert-danger">'+(res.message||'Laporan gagal diproses.')+'</div>');$('#nrp_alert').text(res.message||'Laporan gagal diproses.').show();}}).fail(function(xhr){$('#nrp_result').html('<div class="alert alert-danger">Server error</div>');$('#nrp_alert').text(xhr.responseText||'Server error').show();}).always(function(){$('#btn_filter').prop('disabled',false);});}
$('#btn_default_compare').on('click',function(){defaultCompare();});$('#current_as_of_date').on('change',defaultCompare);$('#form_nrp').on('submit',function(e){e.preventDefault();loadReport();});$('#btn_excel').on('click',function(){window.location='<?=base_admin();?>modul/finance_report/finance_report_neraca_perbandingan_periode_action.php?act=excel&'+qs();});$('#btn_print').on('click',function(){window.open('<?=base_admin();?>modul/finance_report/finance_report_neraca_perbandingan_periode_action.php?act=print&'+qs(),'_blank');});defaultCompare();loadReport();});
</script>
